  ('elementary-7fec267e-moex-00344', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-753c7f7d', 'sub-elementary-7fec267e-04', NULL, 'single_choice', '質疑傳統行政學的理性效率管理模式，而要求應對社會上的弱勢族群實踐公道正義的，是下列那一個？', '["公共選擇理論", "新公共行政", "新公共管理", "新制度理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "949d30e8b296", "answer_pdf_sha1": "f4dab1dc4248", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00345', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-753c7f7d', 'sub-elementary-7fec267e-04', NULL, 'single_choice', '某機關首長找到了一套他認為最有效的管理方法，並且要求機關內所有中階主管一起採用這套管理方法， 卻一直不見成效。從行政學「整合時期」的理論分析，這位首長的領導可能出了什麼問題？', '["管理方式不夠科學，應該強化科學管理", "太過相信存在「最佳法則」，實際上主管面臨不同的環境所適用的管理方式可能不同", "管理方式不夠人性化，主管應該學會關心部屬", "這位首長沒有強力監督每位中階主管的管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "949d30e8b296", "answer_pdf_sha1": "f4dab1dc4248", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00346', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-753c7f7d', 'sub-elementary-7fec267e-04', NULL, 'single_choice', '有關權威之敘述，下列何者正確？', '["巴納德（C.I.Barnard）提出權威接受論，認為權威應視當時情況及事實需要來運用", "韋伯（M.Weber）認為超人權威（charismaticauthority）較符合當代社會之權威模式", "傅麗德（M.P.Follett）提出情勢法則，認為權威必須視受命者是否有能力加以執行", "費堯（H.Fayol）提出14點管理原則（principlesofmanagement），認為最後權力應握於最高領導者 手中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "949d30e8b296", "answer_pdf_sha1": "f4dab1dc4248", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00347', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-753c7f7d', 'sub-elementary-7fec267e-04', NULL, 'single_choice', '行政學整合理論時期（1960年代之後）的主要研究重心是：', '["組織結構及法令規章的靜態性研究", "人員情緒及人際互動的動態性研究", "組織與外部環境彈性適應的生態性研究", "人性心理因素的心態性研究"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "949d30e8b296", "answer_pdf_sha1": "f4dab1dc4248", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00348', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-753c7f7d', 'sub-elementary-7fec267e-04', NULL, 'single_choice', '科技部於民國111年更名為國家科學及技術委員會，此屬於下列何種政府再造類型？', '["科學管理", "公私協力", "公有民營", "組織改制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "949d30e8b296", "answer_pdf_sha1": "f4dab1dc4248", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00349', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-753c7f7d', 'sub-elementary-7fec267e-04', NULL, 'single_choice', '有關公務員廉政倫理規範，下列敘述何者錯誤？', '["遇有請託關說時，應於3日內簽報其長官並知會政風機構", "在偶發而無影響特定權利義務之虞時，可接受長官之獎勵、救助或慰問", "配偶收受財物時，推定為公務員之受贈財物", "正常社交禮俗標準的禮尚往來，同一年度同一來源的受贈財物以新臺幣20,000元為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "949d30e8b296", "answer_pdf_sha1": "f4dab1dc4248", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
